def _resolve_entry_path(spec: dict[str, Any]) -> Path | None:
    direct = spec.get("path")
    if direct:
        path = REPORT_DIR / str(direct)
        return path if path.exists() else None

    pattern = spec.get("pattern")
    if not pattern:
        return None

    matches = [path for path in REPORT_DIR.glob(str(pattern)) if path.is_file()]
    if not matches:
        return None
    return max(matches, key=lambda path: (path.stat().st_mtime, path.name))


def _format_timestamp(path: Path | None) -> str:
    if not path or not path.exists():
        return "缺失"
    return datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")


def _state_for_entry(path: Path | None, stale_hours: int) -> tuple[str, str, str]:
    if not path or not path.exists():
        return "missing", "缺失", "-"
    mtime = datetime.fromtimestamp(path.stat().st_mtime)
    age_hours = max((datetime.now() - mtime).total_seconds() / 3600.0, 0.0)
    if age_hours > float(stale_hours):
        return "stale", f"停更 {age_hours:.1f}h", f"{age_hours:.1f}h"
    return "fresh", "正常", f"{age_hours:.1f}h"


def _build_rows(specs: list[dict[str, Any]]) -> tuple[list[str], dict[str, int]]:
    rows: list[str] = []
    summary = {"fresh": 0, "stale": 0, "missing": 0}
    for spec in specs:
        path = _resolve_entry_path(spec)
        stale_hours = int(spec.get("stale_hours", 24) or 24)
        state, state_label, age_label = _state_for_entry(path, stale_hours)
        summary[state] += 1
        if path:
            link_html = f"<a href='{html.escape(path.name)}'>{html.escape(path.name)}</a>"
        else:
            link_html = "<span class='missing-file'>文件缺失</span>"
        rows.append(
            "<tr class='{state}'>"
            "<td>{label}</td>"
            "<td>{link_html}</td>"
            "<td><span class='pill {state}'>{state_label}</span></td>"
            "<td>{timestamp}</td>"
            "<td>{age_label}</td>"
            "</tr>".format(
                state=state,
                label=html.escape(str(spec["label"])),
                link_html=link_html,
                state_label=html.escape(state_label),
                timestamp=html.escape(_format_timestamp(path)),
                age_label=html.escape(age_label),
            )
        )
    return rows, summary


def _summary_chip(summary: dict[str, int]) -> str:
    return "正常 {fresh} / 停更 {stale} / 缺失 {missing}".format(**summary)


def _render_section(title: str, desc: str, specs: list[dict[str, Any]], *, details: bool = False, open_by_default: bool = False) -> str:
    rows, summary = _build_rows(specs)
    body = """
      <div class=\"section-head\">
        <div>
          <h2>{title}</h2>
          <div class=\"tip\">{desc}</div>
        </div>
        <div class=\"chip\">{summary}</div>
      </div>
      <table>
        <thead>
          <tr><th>面板/导出</th><th>链接</th><th>状态</th><th>实际文件更新时间</th><th>距今</th></tr>
        </thead>
        <tbody>
          {rows}
        </tbody>
      </table>
    """.format(
        title=html.escape(title),
        desc=html.escape(desc),
        summary=html.escape(_summary_chip(summary)),
        rows="".join(rows),
    )
    if details:
        open_attr = " open" if open_by_default else ""
        return f"<details class='card'{open_attr}><summary>{html.escape(title)}</summary>{body}</details>"
    return f"<section class='card'>{body}</section>"


